SELECT COUNT(*)
FROM review_record
WHERE teacher_id = #{teacherId}
AND review_status = #{status}
AND is_deleted = 0
AND create_time >= #{startDate}
AND create_time <= #{endDate}

WITH total_count AS ( SELECT COUNT(*) as total FROM review_record WHERE teacher_id = #{teacherId} AND is_deleted = 0 AND review_status IN (3, 4)
AND create_time >= #{startDate}
AND create_time <= #{endDate}
) SELECT review_status as status, CASE review_status WHEN 3 THEN '审核通过' WHEN 4 THEN '审核未通过' ELSE '未知状态' END as statusName, COUNT(*) as count, ROUND(COUNT(*) * 100.0 / (SELECT total FROM total_count), 1) as percentage, CASE review_status WHEN 3 THEN '#52c41a' WHEN 4 THEN '#ff4d4f' ELSE '#d9d9d9' END as color FROM review_record WHERE teacher_id = #{teacherId} AND is_deleted = 0 AND review_status IN (3, 4)
AND create_time >= #{startDate}
AND create_time <= #{endDate}
GROUP BY review_status ORDER BY CASE review_status WHEN 3 THEN 1 WHEN 4 THEN 2 ELSE 3 END
